parameters.jsCode:
const cluster   = $('Load Cluster').first().json
const templates = $('Load Active Meme Templates').all().map(i => i.json)
const raw       = $('OpenAI — Generate Captions').first().json

let captions = []
try {
  const content = raw.message?.content || raw.choices?.[0]?.message?.content || '[]'
  captions = JSON.parse(content)
  if (!Array.isArray(captions)) captions = captions.memes || []
} catch(e) { captions = [] }

const memes = captions.map((cap, i) => ({
  cluster_id:   cluster.id,
  template_id:  templates[i % templates.length]?.id || null,
  caption:      cap.caption,
  top_text:     cap.top_text || '',
  bottom_text:  cap.bottom_text || '',
  ai_prompt:    `meme for: ${cluster.title}`,
  imgflip_template_id: templates[i % templates.length]?.imgflip_id || null
}))

return [{
  json: {
    org_id:   cluster.org_id,
    run_id:   $('Webhook Trigger').first().json.body.run_id,
    status:   'success',
    memes,
    cluster_id: cluster.id
  }
}]

// Merge imgflip URL back into meme objects
const meme = $input.first().json
const imgflipResult = $('imgflip API').first()?.json
if (imgflipResult?.success) {
  meme.imgflip_url = imgflipResult.data?.url
}
return [{ json: meme }]
